Register-ArgumentCompleter -CommandName pwsh -ScriptBlock {
	param ([string]$wordToComplete)
	if ($wordToComplete.StartsWith('-')) {
		@(
			[System.Management.Automation.CompletionResult]::new('-File', '-File', 'ParameterName', 'If the value of File is "-", the command text is read from standard input.')
			[System.Management.Automation.CompletionResult]::new('-f', '-f', 'ParameterName', 'If the value of File is "-", the command text is read from standard input.')
			[System.Management.Automation.CompletionResult]::new('-Command', '-Command', 'ParameterName', 'Executes the specified commands (and any parameters) as though they were typed at the PowerShell command prompt, and then exits, unless the NoExit parameter is specified.')
			[System.Management.Automation.CompletionResult]::new('-c', '-c', 'ParameterName', 'Executes the specified commands (and any parameters) as though they were typed at the PowerShell command prompt, and then exits, unless the NoExit parameter is specified.')
			[System.Management.Automation.CompletionResult]::new('-ConfigurationName', '-ConfigurationName', 'ParameterName', 'Specifies a configuration endpoint in which PowerShell is run.')
			[System.Management.Automation.CompletionResult]::new('-config', '-config', 'ParameterName', 'Specifies a configuration endpoint in which PowerShell is run.')
			[System.Management.Automation.CompletionResult]::new('-CustomPipeName', '-CustomPipeName', 'ParameterName', 'Specifies the name to use for an additional IPC server (named pipe) used for debugging and other cross-process communication.')
			[System.Management.Automation.CompletionResult]::new('-EncodedCommand', '-EncodedCommand', 'ParameterName', 'Accepts a Base64-encoded string version of a command.')
			[System.Management.Automation.CompletionResult]::new('-e', '-e', 'ParameterName', 'Accepts a Base64-encoded string version of a command.')
			[System.Management.Automation.CompletionResult]::new('-ec', '-ec', 'ParameterName', 'Accepts a Base64-encoded string version of a command.')
			[System.Management.Automation.CompletionResult]::new('-ExecutionPolicy', '-ExecutionPolicy', 'ParameterName', 'Sets the default execution policy for the current session and saves it in the $env:PSExecutionPolicyPreference environment variable.')
			[System.Management.Automation.CompletionResult]::new('-ex', '-ex', 'ParameterName', 'Sets the default execution policy for the current session and saves it in the $env:PSExecutionPolicyPreference environment variable.')
			[System.Management.Automation.CompletionResult]::new('-ep', '-ep', 'ParameterName', 'Sets the default execution policy for the current session and saves it in the $env:PSExecutionPolicyPreference environment variable.')
			[System.Management.Automation.CompletionResult]::new('-InputFormat', '-InputFormat', 'ParameterName', 'Describes the format of data sent to PowerShell.')
			[System.Management.Automation.CompletionResult]::new('-inp', '-inp', 'ParameterName', 'Describes the format of data sent to PowerShell.')
			[System.Management.Automation.CompletionResult]::new('-if', '-if', 'ParameterName', 'Describes the format of data sent to PowerShell.')
			[System.Management.Automation.CompletionResult]::new('-Interactive', '-Interactive', 'ParameterName', 'Present an interactive prompt to the user.')
			[System.Management.Automation.CompletionResult]::new('-i', '-i', 'ParameterName', 'Present an interactive prompt to the user.')
			[System.Management.Automation.CompletionResult]::new('-Login', '-Login', 'ParameterName', 'On Linux and macOS, starts PowerShell as a login shell, using /bin/sh to execute login profiles such as /etc/profile and ~/.')
			[System.Management.Automation.CompletionResult]::new('-l', '-l', 'ParameterName', 'On Linux and macOS, starts PowerShell as a login shell, using /bin/sh to execute login profiles such as /etc/profile and ~/.')
			[System.Management.Automation.CompletionResult]::new('-MTA', '-MTA', 'ParameterName', 'Start PowerShell using a multi-threaded apartment.')
			[System.Management.Automation.CompletionResult]::new('-NoExit', '-NoExit', 'ParameterName', 'Does not exit after running startup commands.')
			[System.Management.Automation.CompletionResult]::new('-noe', '-noe', 'ParameterName', 'Does not exit after running startup commands.')
			[System.Management.Automation.CompletionResult]::new('-NoLogo', '-NoLogo', 'ParameterName', 'Hides the copyright banner at startup of interactive sessions.')
			[System.Management.Automation.CompletionResult]::new('-nol', '-nol', 'ParameterName', 'Hides the copyright banner at startup of interactive sessions.')
			[System.Management.Automation.CompletionResult]::new('-NonInteractive', '-NonInteractive', 'ParameterName', 'Does not present an interactive prompt to the user.')
			[System.Management.Automation.CompletionResult]::new('-noni', '-noni', 'ParameterName', 'Does not present an interactive prompt to the user.')
			[System.Management.Automation.CompletionResult]::new('-NoProfile', '-NoProfile', 'ParameterName', 'Does not load the PowerShell profiles.')
			[System.Management.Automation.CompletionResult]::new('-nop', '-nop', 'ParameterName', 'Does not load the PowerShell profiles.')
			[System.Management.Automation.CompletionResult]::new('-OutputFormat', '-OutputFormat', 'ParameterName', 'Determines how output from PowerShell is formatted.')
			[System.Management.Automation.CompletionResult]::new('-o', '-o', 'ParameterName', 'Determines how output from PowerShell is formatted.')
			[System.Management.Automation.CompletionResult]::new('-of', '-of', 'ParameterName', 'Determines how output from PowerShell is formatted.')
			[System.Management.Automation.CompletionResult]::new('-SettingsFile', '-SettingsFile', 'ParameterName', 'Overrides the system-wide "powershell.')
			[System.Management.Automation.CompletionResult]::new('-settings', '-settings', 'ParameterName', 'Overrides the system-wide "powershell.')
			[System.Management.Automation.CompletionResult]::new('-SSHServerMode', '-SSHServerMode', 'ParameterName', 'Used in sshd_config for running PowerShell as an SSH subsystem.')
			[System.Management.Automation.CompletionResult]::new('-sshs', '-sshs', 'ParameterName', 'Used in sshd_config for running PowerShell as an SSH subsystem.')
			[System.Management.Automation.CompletionResult]::new('-STA', '-STA', 'ParameterName', 'Start PowerShell using a single-threaded apartment.')
			[System.Management.Automation.CompletionResult]::new('-Version', '-Version', 'ParameterName', 'Displays the version of PowerShell.')
			[System.Management.Automation.CompletionResult]::new('-v', '-v', 'ParameterName', 'Displays the version of PowerShell.')
			[System.Management.Automation.CompletionResult]::new('-WindowStyle', '-WindowStyle', 'ParameterName', 'Sets the window style for the session.')
			[System.Management.Automation.CompletionResult]::new('-w', '-w', 'ParameterName', 'Sets the window style for the session.')
			[System.Management.Automation.CompletionResult]::new('-WorkingDirectory', '-WorkingDirectory', 'ParameterName', 'Sets the initial working directory by executing at startup.')
			[System.Management.Automation.CompletionResult]::new('-wd', '-wd', 'ParameterName', 'Sets the initial working directory by executing at startup.')
			[System.Management.Automation.CompletionResult]::new('-Help', '-Help', 'ParameterName', 'Displays help for pwsh.')
			[System.Management.Automation.CompletionResult]::new('-?', '-?', 'ParameterName', 'Displays help for pwsh.')
			[System.Management.Automation.CompletionResult]::new('/?', '/?', 'ParameterName', 'Displays help for pwsh.')
		) | ? CompletionText -Like $wordToComplete*
	}
}
